171	func (s *Store) Run(ctx context.Context, definitionID string) (RunRecord, error) {
172		def, doc, err := s.Validate(definitionID)
173		if err != nil {
174			return RunRecord{}, err
175		}
176		if def.Executor.Kind == ExecutorKindAgent {
177			if s.AgentRunner == nil {
178				return RunRecord{}, fmt.Errorf("agent runner not configured for exec definition %q", def.ID)
179			}
180	
181			var promptFile, promptText string
182			if len(def.Executor.Command) > 0 {
183				promptFile = def.Executor.Command[0]
184			} else {
185				promptText = def.Executor.Env["DDX_AGENT_PROMPT"]
186			}
187	
188			workDir := def.Executor.Cwd
189			if workDir == "" {
190				workDir = s.WorkingDir
191			} else if !filepath.IsAbs(workDir) {
192				workDir = filepath.Join(s.WorkingDir, workDir)
193			}
194	
195			var timeout time.Duration
196			if def.Executor.TimeoutMS > 0 {
197				timeout = time.Duration(def.Executor.TimeoutMS) * time.Millisecond
198			}
199	
200			sessionID := genAgentSessionID()
201			opts := agent.RunOptions{
202				Harness:    def.Executor.Env["DDX_AGENT_HARNESS"],
203				Prompt:     promptText,
204				PromptFile: promptFile,
205				Correlation: map[string]string{
206					"definition_id": def.ID,
207					"artifact_ids":  strings.Join(def.ArtifactIDs, ","),
208					"session_id":    sessionID,
209				},
210				Model:   def.Executor.Env["DDX_AGENT_MODEL"],
211				Effort:  def.Executor.Env["DDX_AGENT_EFFORT"],
212				Timeout: timeout,
213				WorkDir: workDir,
214			}
215	
216			start := time.Now().UTC()
217			agentResult, agentErr := s.AgentRunner.Run(opts)
218			finished := time.Now().UTC()
219	
220			status := StatusSuccess
221			exitCode := 0
222			var stdout, stderr string
223			if agentErr != nil {
224				status = StatusErrored
225				exitCode = 1
226				stderr = agentErr.Error()
227			} else {
228				exitCode = agentResult.ExitCode
229				stdout = strings.TrimSpace(agentResult.Output)
230				stderr = strings.TrimSpace(agentResult.Stderr)
231				if exitCode != 0 {
232					if exitCode == -1 && strings.Contains(agentResult.Error, "timeout") {
233						status = StatusTimedOut
234					} else {
235						status = StatusFailed
236					}
237				}
238			}
239	
240			runID := fmt.Sprintf("%s@%s-%d", def.ID, start.Format(time.RFC3339Nano), atomic.AddUint64(&s.runCounter, 1))
241			record := RunRecord{
242				RunManifest: RunManifest{
243					RunID:          runID,
244					DefinitionID:   def.ID,
245					ArtifactIDs:    def.ArtifactIDs,
246					StartedAt:      start,
247					FinishedAt:     finished,
248					Status:         status,
249					ExitCode:       exitCode,
250					MergeBlocking:  def.Required && status != StatusSuccess,
251					AgentSessionID: sessionID,
252					Attachments:    runAttachmentRefs(s.WorkingDir, runID),
253					Provenance:     provenance(),
254				},
255				Result: RunResult{
256					Stdout: stdout,
257					Stderr: stderr,
258				},
259			}
260			if saveErr := s.saveRunRecord(record); saveErr != nil {
261				return RunRecord{}, saveErr
262			}
263			return record, nil
264		}
265	
266		cwd := s.WorkingDir
267		if def.Executor.Cwd != "" {
268			if filepath.IsAbs(def.Executor.Cwd) {
269				cwd = def.Executor.Cwd
270			} else {
271				cwd = filepath.Join(s.WorkingDir, def.Executor.Cwd)
272			}
273		}
274	
275		cmd := osexec.CommandContext(ctx, def.Executor.Command[0], def.Executor.Command[1:]...)
276		cmd.Dir = cwd
277		if len(def.Executor.Env) > 0 {
278			cmd.Env = append(os.Environ(), flattenEnv(def.Executor.Env)...)
279		}
280	
281		start := time.Now().UTC()
282		stdout, stderr, runErr := captureCommand(cmd)
283		finished := time.Now().UTC()
284		duration := finished.Sub(start)
285	
286		result := RunResult{
287			Stdout: strings.TrimSpace(stdout),
288			Stderr: strings.TrimSpace(stderr),
289		}
290		value, unit := normalizeMeasurement(stdout)
291		if unit == "" && def.Result.Metric != nil {
292			unit = def.Result.Metric.Unit
293		}
294		if unit != "" || value != 0 {
295			result.Parsed = true
296			result.Value = value
297			result.Unit = unit
298			result.Metric = &MetricObservation{
299				ArtifactID:   doc.ID,
300				DefinitionID: def.ID,
301				ObservedAt:   start,
302				Value:        value,
303				Unit:         unit,
304				Samples:      []float64{value},
305			}
306		}
307	
308		status := StatusSuccess
309		exitCode := 0
310		if runErr != nil {
311			switch {
312			case errors.Is(runErr, context.DeadlineExceeded):
313				status = StatusTimedOut
314			default:
315				status = StatusFailed
316			}
317			var exitErr *osexec.ExitError
318			if errors.As(runErr, &exitErr) {
319				exitCode = exitErr.ExitCode()
320			} else {
321				exitCode = 1
322			}
323		}
324		if result.Metric != nil {
325			result.Metric.Status = metricStatusForRun(status)
326			if status == StatusSuccess {
327				result.Metric.Comparison = ComparisonResult{
328					Baseline:  value,
329					Delta:     0,
330					Direction: def.Evaluation.Comparison,
331				}
332			}
333		}
334	
335		runID := fmt.Sprintf("%s@%s-%d", def.ID, start.Format(time.RFC3339Nano), atomic.AddUint64(&s.runCounter, 1))
336		record := RunRecord{
337			RunManifest: RunManifest{
338				RunID:         runID,
339				DefinitionID:  def.ID,
340				ArtifactIDs:   def.ArtifactIDs,
341				StartedAt:     start,
342				FinishedAt:    finished,
343				Status:        status,
344				ExitCode:      exitCode,
345				MergeBlocking: def.Required && status != StatusSuccess,
346				Attachments:   runAttachmentRefs(s.WorkingDir, runID),
347				Provenance:    provenance(),
348			},
349			Result: result,
350		}
351		if writeErr := s.saveRunRecord(record); writeErr != nil {
352			return RunRecord{}, writeErr
353		}
354		_ = duration
355		return record, nil
356	}
