432			return err
433		}
434		if err := os.WriteFile(filepath.Join(tempDir, "stderr.log"), []byte(rec.Result.Stderr), 0o644); err != nil {
435			return err
436		}
437		if err := syncPath(tempDir); err != nil {
438			return err
439		}
440		finalDir := filepath.Join(s.RunsDir, rec.RunID)
