467	func withPathLock(path string, fn func() error) error {
468		lockDir := path
469		deadline := time.Now().Add(5 * time.Second)
470		for {
471			err := os.Mkdir(lockDir, 0o755)
472			if err == nil {
473				defer os.RemoveAll(lockDir)
474				return fn()
475			}
476			if time.Now().After(deadline) {
477				return fmt.Errorf("exec lock timeout for %s", path)
478			}
479			time.Sleep(20 * time.Millisecond)
480		}
481	}
