483	func atomicWriteFile(path string, data []byte, perm os.FileMode) error {
484		tmp, err := os.CreateTemp(filepath.Dir(path), "."+filepath.Base(path)+".tmp-*")
485		if err != nil {
486			return err
487		}
488		tmpPath := tmp.Name()
489		defer os.Remove(tmpPath)
490		if _, err := tmp.Write(data); err != nil {
491			tmp.Close()
492			return err
493		}
494		if err := tmp.Sync(); err != nil {
495			tmp.Close()
496			return err
497		}
498		if err := tmp.Close(); err != nil {
499			return err
500		}
501		if err := os.Chmod(tmpPath, perm); err != nil {
502			return err
503		}
504		return os.Rename(tmpPath, path)
505	}
